class Solution:
    def powerfulIntegers(self, x, y, bound):
        # Independent approach: precompute all powers of x and of y up to bound,
        # then take every pairwise sum within bound.
        def powers(base):
            ps = []
            v = 1
            while v <= bound:
                ps.append(v)
                if base == 1:
                    break
                v *= base
            return ps
        if bound < 2:
            return []
        xs = powers(x)
        ys = powers(y)
        res = set()
        for a in xs:
            for b in ys:
                if a + b <= bound:
                    res.add(a + b)
        return list(res)

