var powerfulIntegers = function(x, y, bound) {
    const res = new Set();
    let i = 1;
    while (i <= bound) {
        let j = 1;
        while (i + j <= bound) {
            res.add(i + j);
            if (y === 1) break;
            j *= y;
        }
        if (x === 1) break;
        i *= x;
    }
    return Array.from(res);
};
